&lt;p&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;span data-contrast=&quot;auto&quot;&gt;EHS&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559739&amp;quot;:60}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Design and implement&amp;nbsp;Freeform&#39;s&amp;nbsp;EHS management system across Cal/OSHA, federal OSHA,&amp;nbsp;and similar industry regulations&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559739&amp;quot;:0}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;auto&quot;&gt;Develop standards for&amp;nbsp;metal powder safety: storage, loading, sieving,&amp;nbsp;depowdering, recycling, and disposal of reactive&amp;nbsp;and non-reactive&amp;nbsp;alloys&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559739&amp;quot;:0}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
